public class CleanupService(ILogger<CleanupService> logger) : BackgroundService
{
    protected override async Task ExecuteAsync(CancellationToken stoppingToken)
    {
        using var timer = new PeriodicTimer(TimeSpan.FromHours(1));

        // Chạy ngay 1 lần trước khi vào loop
        await DoCleanupAsync(stoppingToken);

        // Mỗi 1h — không overlap, auto-skip nếu slow
        while (await timer.WaitForNextTickAsync(stoppingToken))
        {
            try { await DoCleanupAsync(stoppingToken); }
            catch (Exception ex) when (ex is not OperationCanceledException)
            {
                logger.LogError(ex, "Cleanup thất bại");
                // Tiếp tục loop — không crash service
            }
        }
    }

    private async Task DoCleanupAsync(CancellationToken ct) { /* ... */ }
}

